import{_ as a,o as t,c as n,a3 as o}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"38D. Annual Leave","description":"","frontmatter":{"title":"38D. Annual Leave","eba":"Mental Health Services 2024-2028","topics":["leave","annual-leave","hours","preliminary"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/leave/38D-annual-leave.md","filePath":"ebas/mental-health/common-terms/leave/38D-annual-leave.md"}'),r={name:"ebas/mental-health/common-terms/leave/38D-annual-leave.md"};function l(s,e,i,h,p,m){return t(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="_38d-annual-leave" tabindex="-1">38D. Annual Leave <a class="header-anchor" href="#_38d-annual-leave" aria-label="Permalink to &quot;38D. Annual Leave&quot;">​</a></h1><p>Note: This clause does not apply to casual Employees. 38D.1. Basic Entitlement to Annual Leave – amount of leave</p><p><strong>(a)</strong> An Employee is entitled to 190 hours paid annual leave for each year of service.</p><p><strong>(b)</strong> Part-time Employees are entitled to annual leave on a pro-rata basis. 38D.2. Additional Entitlement to Annual Leave</p><p><strong>(a)</strong> A weekend worker is entitled to a further 38 hours’ paid annual leave in each year of service as follows:</p><p><strong>(iv)</strong> For Full-Time Employees: <strong>(A)</strong> At the rate of 3.8 hours for each week in which ordinary hours were worked on a weekend (or part thereof), up to a maximum of 38 hours (10 weekends).</p><p><strong>(v)</strong> For Part-Time Employees <strong>(A)</strong> As a proportion of 3.8 hours for each week in which ordinary hours were worked on a weekend (or part thereof) up to a maximum of 10 weekends. Example: If a part-time Employee works 24 hours in a week and those 24 hours include hours worked on a weekend, they would accrue a proportion of</p><p><strong>3.8</strong> hours as follows: 24/38 x 3.8 = 2.4 hours.</p><p><strong>(b)</strong> A</p><p><strong>(c)</strong> Annual Leave accrues progressively during a year of service according to the employees ordinary hours of work and accumulates from year to year.</p><p><strong>(d)</strong> Savings - Weekend worker as at 30 June 2022 (Section 2 Employees only)</p><p>If an Employee was accruing 6 weeks annual leave as at 30 June 2022 (or would have been but for the operation of an arrangement under <a href="/eba/ebas/mental-health/common-terms/workplace-rights/65-flexible-working-arrangements.html">clause 65</a> (Flexible Working Arrangements) or <a href="/eba/ebas/mental-health/common-terms/workplace-rights/66-individual-flexible-working-arrangements.html">clause 66</a> (Individual Flexible Working Arrangements) or an absence from work on parental leave), the Employee will continue to accrue six weeks of annual leave unless or until:</p><p><strong>(i)</strong> the arrangement at sub-clause 38D.2(a) or (b) is more beneficial for the Employee</p><p><strong>(ii)</strong> the Employee changes Employers</p><p><strong>(iii)</strong> the Employee requests (and the Employer agrees) to move the Employee from full time to part-time employment other than as part of a flexible working arrangement, family and domestic violence arrangement or reduced hours on return from parental leave); or</p><p><strong>(iv)</strong> the Employee initiates a change that means they no longer perform weekend work. For example: <strong>(A)</strong> where an Employee requests a change to a different role that does not require the performance of weekend work</p><p><strong>(B)</strong> where an Employee requests to move from a rotating or similar roster that includes weekends, to fixed shifts that do not include weekend work; or <strong>(C)</strong> where an Employee (at their request) relocates to a ward with a different system of work (for the removal of doubt, this does not include where an Employee requests to move to a ward with the same general system of work). 38D.3. Taking paid annual leave</p><p><strong>(a)</strong> Paid annual leave may be taken for a period agreed between an Employee and their Employer.</p><p><strong>(b)</strong> The Employer must publish how the Employee is to make an annual leave request.</p><p><strong>(c)</strong> The Employer must not unreasonably refuse to agree to a request by the Employee to take paid annual leave.</p><p><strong>(d)</strong> Once annual leave is approved, it must not be unilaterally changed by the Employer. Where extraordinary circumstances arise, such that the Employer wishes the Employee to change the timing of their approved leave, any change may only occur through consultation and agreement.</p><p><strong>(e)</strong> Where it is likely the leave request will be rejected, the Employer and Employee will consult on alternate leave days within the 10 day period or, in the case of high demand holiday period, the period between the date specified at 38D.4(ii) and 38D.4(iii).</p><p><strong>(f)</strong> Where the paid annual leave is for a period other than a high demand holiday period:</p><p><strong>(i)</strong> The Employee will submit a written request for annual leave at least 6 weeks prior to the first day of the proposed leave period/s unless it is not reasonable to do so in the circumstances; and</p><p><strong>(ii)</strong> within ten (10) week days of the leave request, the Employer will notify the Employee in writing that their annual leave request is approved or, if not approved, the reasons for the leave not being approved. 38D.4. High Demand Holiday Periods</p><p><strong>(a)</strong> An employer will develop and publish to affected Employees (which may be a specific ward or work area) requirements for a high demand holiday period. Where this occurs, the requirement must:</p><p><strong>(i)</strong> Identify the high demand holiday period</p><p><strong>(ii)</strong> Identify the date by which a written request for annual leave should be submitted; and</p><p><strong>(iii)</strong> Identify the date by which the Employer will notify the Employee in writing that their annual leave request is approved or, if not approved, the reasons for the leave not being approved.</p><p><strong>(iv)</strong> In determining applications for high-demand periods, the Employer will consider all the circumstances including but not limited to: <strong>(A)</strong> the Employer&#39;s operational needs <strong>(B)</strong> the Employee&#39;s family responsibilities; and</p><p><strong>(C)</strong> whether previous leave applications for the same high-demand period were or were not successful.</p><p>Example – A ward generally receives more applications for annual leave over school term breaks than it can accommodate. This means that school term breaks are ‘high demand periods’ for that ward within the meaning of this sub clause 38D.4 and the Manager must publish the information specified above at 38D.4(i) to (iii) and, when determining the applications, apply the considerations at 38D.4(iv).</p><p>Short periods of annual leave Paid annual leave under this clause can be taken in periods less than an Employee’s ordinary fortnight (short period), including single days in which case any notice period may be waived by agreement. 38D.5. Payment for leave</p><p><strong>(a)</strong> Employees will receive their ordinary pay and any amount required by clause 38D.7 (Annual leave loading or penalties) during periods of annual leave. Ordinary pay for the purposes of this clause means remuneration for the Employee’s normal weekly number of hours of work calculated at the ordinary time rate of pay provided that:</p><p><strong>(i)</strong> where an Employee has performed higher duties for an aggregate period of three months or more in a twelve (12) month period, ordinary pay will be adjusted proportionally to reflect the period during which higher duties were performed; and</p><p><strong>(ii)</strong> normal weekly hours for a part time Employee who performs additional shifts will reflect the additional hours worked over the 12 month period.</p><p><strong>(b)</strong> Payment for paid annual leave will be in advance for the period of such leave except for a short period (as defined in clause 38D.5). 38D.6. Annual leave loading or penalties</p><p><strong>(a)</strong> In addition to ordinary pay (as defined) an Employee will receive the higher of:</p><p><strong>(i)</strong> leave loading of 17.5% calculated on the relevant rate of salary prescribed in Appendix 2, subject to the cap at sub-clause (b), or</p><p><strong>(ii)</strong> the payments listed below which the Employee would have received had the Employee not been on leave, for each week of leave: <strong>(A)</strong> shift work allowances (<a href="/eba/ebas/mental-health/rpn-pen-mho/allowances/84-shift-allowances.html">clauses 84</a>, 119, 157 &amp; 194). <strong>(B)</strong> rates for Saturday, Sunday (<a href="/eba/ebas/mental-health/rpn-pen-mho/allowances/83-saturday-and-sunday-work.html">clause 83</a>, 130, 177, 209); <strong>(C)</strong> qualification allowance (<a href="/eba/ebas/mental-health/rpn-pen-mho/allowances/81-qualification-allowance.html">clause 81</a> &amp; 117); <strong>(D)</strong> uniform allowances (<a href="/eba/ebas/mental-health/rpn-pen-mho/allowances/86-uniform-and-laundry-allowance.html">clause 86</a> &amp; 121).</p><p><strong>(b)</strong> Leave loading under sub-clause 38D.7(a)(i) is payable on:</p><p><strong>(i)</strong> a maximum of 190 hours in respect of any year of employment, and</p><p><strong>(ii)</strong> the Employee’s weekly ordinary pay subject to the cap (as defined); and</p><p><strong>(iii)</strong> the cap under sub-clause 38D.7(b)(ii) is the relevant ‘Annual Leave Loading Cap’ contained within <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> where applicable.</p><p><strong>(c)</strong> To determine which payments the Employee would have received had the Employee not been on leave for the purpose of sub-clause 38D.7(a)(ii), this will be done either by:</p><p><strong>(iv)</strong> the projected roster, being the roster the Employee would have worked had they not been on leave, or</p><p><strong>(v)</strong> where there is no projected roster, the rosters for the twelve weeks immediately preceding the leave excluding any period during which the Employee was not on the roster (for example, because of attendance at approved Professional Development or another form of paid leave). 38D.7. Employee not taken to be on paid annual leave at certain times</p><p><strong>(a)</strong> Public Holidays</p><p>See also <a href="/eba/ebas/mental-health/rpn-pen-mho/leave/98-public-holidays.html">clauses 98</a>, 135, 179 and 213(Public Holidays)</p><p>If an Employee takes paid annual leave during a period that includes a public holiday, the Employee is taken not be on paid annual leave on that day.</p><p><strong>(b)</strong> Other Periods of Leave See also <a href="/eba/ebas/mental-health/common-terms/leave/38A-personal-leave.html">clause 38A</a> (Personal Leave) and 44 (Compassionate Leave)</p><p><strong>(i)</strong> An Employee may take other types of leave, such as personal leave or compassionate leave whilst on annual leave. An Employee is taken not to be on paid annual leave whilst on other leave and the Employee’s paid annual leave accrual will be amended to reflect this. These provisions do not apply to unpaid parental leave.</p><p><strong>(i)</strong> An Employee taking personal leave whilst on annual leave will provide the Employer with evidence in accordance with <a href="/eba/ebas/mental-health/common-terms/leave/38A-personal-leave.html">clause 38A</a> (Personal Leave).</p><p><strong>(ii)</strong> Where an Employee takes other leave during annual leave, any annual leave loading received for a period that is no longer annual leave is taken to have been paid in advance as required in <a href="/eba/ebas/mental-health/common-terms/leave/38B-personal-leave-pool.html">clause 38B.6</a> (Payment for Leave) or may be deducted from any payment required to be made under <a href="/eba/ebas/mental-health/common-terms/leave/38B-personal-leave-pool.html">clause 38B.9</a> (Effect of termination on annual leave). 38D.8. Effect of termination on annual leave</p><p><strong>(a)</strong> Where an Employee’s employment ends for any reason, the Employer must pay to the Employee any untaken accrued annual leave. The amount payable to the Employee is the amount the Employee would have received had the Employee taken the leave at the time of termination, including any payment under <a href="/eba/ebas/mental-health/common-terms/leave/38B-personal-leave-pool.html">clause 38B.7</a> (Annual leave loading or penalties).</p><p><strong>(b)</strong> If annual leave has been taken in advance and, at the time the employment terminates, the Employee has a negative paid annual leave accrual, the Employer may deduct a sum equal to the negative annual leave accrual (at the amount paid at the time the annual leave was taken in advance) from any remuneration payable to the Employee upon termination of employment. 38D.9. Excess annual leave accruals</p><p><strong>(a)</strong> General provision</p><p><strong>(i)</strong> An Employee has an excess leave accrual where the Employee has two years or more of annual leave entitlement accrued in accordance with this clause 38D.</p><p><strong>(ii)</strong> If an Employee has an excess leave accrual, the Employer or the Employee may seek to confer with the other and genuinely try to reach agreement on how to reduce or eliminate the excess leave accrual.</p><p><strong>(iii)</strong> ‘Genuinely trying to reach agreement’ will include:</p><p><strong>(A)</strong> providing the Employee a reasonable opportunity to submit a plan to reduce the leave to not less than eight (8) weeks within six months, subject to (ii) below; and <strong>(B)</strong> the Employer not unreasonably refusing to agree to a leave reduction plan which includes saving leave for an extended vacation within 12 months of the date of agreement to the leave reduction plan.</p><p><strong>(iv)</strong> The leave reduction plan is to be in writing and signed by both the Employer and the Employee.</p><p><strong>(b)</strong> Excess Annual leave accruals – no agreement reached</p><p><strong>(i)</strong> Direction by Employer Where the Employer has genuinely tried to reach agreement with an Employee under clause 38D.10(a) but agreement is not reached (including because the Employee refuses to confer), the Employer may direct the Employee in writing to take one or more periods of paid annual leave.</p><p><strong>(i)</strong> However, in directing that the Employee take leave under this subclause 38D.10(b): <strong>(A)</strong> the Employee cannot be directed to reduce the accrued leave to less than eight (8) weeks <strong>(B)</strong> the Employer cannot require an Employee to take any period of paid annual leave of less than one week <strong>(C)</strong> the Employer cannot require the Employee to take a period of paid annual leave beginning less than 8 weeks or more than 12 months after the direction is given; and <strong>(D)</strong> the direction must not be inconsistent with any leave arrangement agreed by the Employer and Employee.</p><p><strong>(iii)</strong> Where the Employer issues a Direction Where the Employer issues a direction to the Employee to take paid annual leave in accordance with paragraph (a): <strong>(A)</strong> the Employee must take paid annual leave in accordance with that direction; and <strong>(B)</strong> the Employee may request to take a period of paid annual leave as if the direction had not been given.</p><p><strong>(iv)</strong> Request by Employee for Leave If the Employee has genuinely tried to reach agreement with the Employer under subclause 38D.10(a)(ii) but agreement is not reached (including because the Employer refuses to confer) the Employee may give a written notice to the Employer requesting to take one or more periods of paid annual leave. However, a notice under this subclause 38D.10: <strong>(A)</strong> may only be given if the Employee has had an excess leave accrual for more than 6 months at the time of giving the notice <strong>(B)</strong> may only be given if the Employee has not been given a direction under subclause 38D.10 that, when any other paid annual leave arrangements are taken into account would eliminate the Employee&#39;s excess accrual <strong>(C)</strong> must not, if granted, result in the Employee&#39;s remaining accrued entitlement to paid annual leave being, at any time, less than 6 weeks when other paid annual leave arrangements are taken into account</p><p><strong>(D)</strong> must not provide for the employee to take any period of paid annual leave of less than one week <strong>(E)</strong> must not provide for the employee to take a period of paid annual leave beginning less than 8 weeks or more than 12 months, after the notice is given <strong>(F)</strong> must not be inconsistent with any leave arrangement agreed by the Employer and Employee; and <strong>(G)</strong> must not be for more than 1 full year&#39;s entitlement to annual leave as prescribed by 38D.1 and 38D.2 above.</p><p><strong>(c)</strong> Where the Employee requests leave by notice</p><p>Where the Employee gives written notice to the Employer to take one or more periods of paid annual leave in accordance with paragraph 38D.10(b)(i), the Employer must grant paid annual leave requested by the notice under paragraph (c).</p><p><strong>(d)</strong> Disputes regarding excess annual leave Without limiting the Dispute Resolution Procedure of the Agreement, either an Employee or Employer (or their representative/s) may refer a dispute about the following matters to the Commission:</p><p><strong>(i)</strong> a dispute about whether the Employer or Employee has requested a meeting and genuinely tried to reach agreement</p><p><strong>(ii)</strong> a dispute about whether the Employer has unreasonable refused to agree to a request by the Employee to take paid annual leave; and</p><p><strong>(iii)</strong> a dispute about whether a direction to take leave complies with the clause. 38D.10. Cashing Out of Annual Leave An Employee may, with the consent of the Employer, choose to cash out paid annual leave in accordance with this clause.</p><p><strong>(a)</strong> Written request and written agreement An Employee wishing to cash out annual leave must make a written request to the Employer. Where the Employer agrees to that request, the Employee and the Employer will record the agreement in writing.</p><p><strong>(b)</strong> Terms of agreement must comply with terms A written agreement must comply with the following terms:</p><p><strong>(i)</strong> paid annual leave must not be cashed out if the cashing out would result in the Employee’s remaining accrued entitlement to paid leave being less than one years&#39; accrual of annual leave each cashing out of a particular amount of paid annual leave must be by a separate agreement in writing between the Employer and the Employee; and</p><p><strong>(ii)</strong> the Employee must be paid at least the full amount that would have been payable to the Employee had the Employee taken the leave that the Employee has forgone, including</p><p><strong>(iii)</strong> annual leave loading and superannuation to the Employee’s nominated Fund; and</p><p><strong>(iv)</strong> an Employee cannot cash out more than 2 weeks paid annual leave in any 12-month period.</p><p><strong>(c)</strong> Payments made in accordance with this clause extinguish an Employee&#39;s right to access annual leave or receive further payment for the period of annual leave paid out.</p><p><strong>38D.12</strong> Part-time Employees – cashing out of annual leave where contracted EFT fraction has reduced A part-time Employee that has reduced their EFT fraction, may request to cash out accrued annual leave in conjunction with taking a period of annual leave so that the total payment for the period is equivalent to the previous EFT fraction. The request and any agreement must comply with the requirements of clause 38D.11 above save that:</p><p><strong>(a)</strong> the requirement that paid annual leave must not be cashed out if the cashing out would result in the Employee’s remaining accrued entitlement to paid leave being less than six weeks calculated using the new EFT fraction; and</p><p><strong>(b)</strong> the limit on cashing out no more than 2 weeks annual leave will not apply</p><p>Example: A part-time Employee recently reduced their contracted EFT from 32 hours per week to 16 hours per week. The Employee wishes to take two weeks annual leave. The Employee&#39;s payment for annual leave taken would be 32 hours&#39; pay (16 hours per week multiplied by 2), plus annual leave loading. The Employee has 160 hours of accrued annual leave (i.e. 5 weeks&#39; leave at their previous EFT, or 10 weeks&#39; leave at their new EFT), before taking or cashing out any annual leave. Subject to the Employee complying with this clause, the Employee may elect to cash out an additional 32 hours&#39; annual leave (plus annual leave loading), at the same time as taking annual leave, so that the total paid to the Employee during the period of leave is:</p><p><strong>(a)</strong> 32 hours&#39; pay (16 hours per week multiplied by 2), plus annual leave loading, for annual leave taken; plus 32 hours&#39; pay, plus annual leave loading, for annual leave cashed out. At the end of the annual leave period, the Employee retains 6 weeks&#39; annual leave, at the Employee&#39;s part-time hours. That is, the Employee will have: 160 hours accrued prior to the leave period, minus 32 hours taken, minus 32 hours cashed out = 96 hours (16 hours multiplied by 6 weeks) accrued annual leave at the end of the leave period.</p><p>Plain language terms: holidays, vacation, recreation leave, holiday pay.</p>',87)])])}const c=a(r,[["render",l]]);export{d as __pageData,c as default};
